import React, { useState, useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { Switch, Route, Redirect, useLocation } from 'react-router-dom';

//view

import {
  HrTimestampList,
  EditTimestamp,
  OtRequest,
  HrEditEmployee,
  HrEmployee,
  HrReport,
  HrReportDaily,
  HrDashboard,
  HrAddEmployee,
  HrSalaryList,
  HrAddSalary,
  HrSalaryDetail,
  HrEmployeeDetail,
  AddOt,
  EditOt,
} from '../views/Humen';
//

import { HomeNavbar } from '../components/Nevbars';
import { MainFooter } from '../components/Footers';
import { MainSidebar } from '../components/Sidebar';
import { NotFound } from '../components/Error';
// import accessRight from '../utils/functions/accessRight';
import * as actions from '../redux/actions';
import Loading from 'components/Loading';

export function Humen() {
  const module = 'HUMEN';
  const prefix = '/humen';
  const name = 'humen';
  const dispatch = useDispatch();
  const { pathname } = useLocation();

  const me = useSelector((state) => state.me);

  const [isMobileNavOpen, setMobileNavOpen] = useState(false);
  const handleOnMobileNavOpen = () => {
    setMobileNavOpen(true);
  };
  const handleOnMobileNavClose = () => {
    setMobileNavOpen(false);
  };
  useEffect(() => {
    dispatch(actions.meGet());

    return () => {};
  }, []);
  if (!me.userData) {
    return <Loading />;
  }
  return (
    <div className="min-h-screen">
      <MainSidebar
        onMobileClose={handleOnMobileNavClose}
        openMobile={isMobileNavOpen}
        me={me}
      />
      <HomeNavbar onMobileNavOpen={handleOnMobileNavOpen} />

      <div className="relative lg:ml-56  min-h-screen  pt-2 px-8 ">
        <div className="py-4">
          <Switch>
            {' '}
            <Route exact path={`${prefix}/report`}>
              <HrReport title="REPORT" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/reportDaily`}>
              <HrReportDaily title="REPORT DAILY" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/timestamp`}>
              <HrTimestampList title="TIMESTAMP LIST" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/timestamp-dashboard`}>
              <HrDashboard title="DASHBOARD" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/timestamp/edit/:id`}>
              <EditTimestamp title="EDIT" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/ot-request`}>
              <OtRequest title="OT REQUEST" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/ot-request/add`}>
              <AddOt title="ADD OT" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/ot-request/edit/:id`}>
              <EditOt title="EDIT OT" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/employee`}>
              <HrEmployee title="EMPLOYEE" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/employee/detail/:id`}>
              <HrEmployeeDetail title="EMPLOYEE DETAIL" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/salarylist`}>
              <HrSalaryList title="SALARY LIST" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/salarylist/detail/:id`}>
              <HrSalaryDetail title="SALARY DETAIL" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/salarylist/add`}>
              <HrAddSalary title="ADD SALARY" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/employee/add`}>
              <HrAddEmployee title="ADD EMPLOYEE" subtitle={name} />
            </Route>
            <Route exact path={`${prefix}/employee/edit/:id`}>
              <HrEditEmployee title="EDIT" subtitle={name} />
            </Route>
            <Route path="*">
              <NotFound />
            </Route>
          </Switch>
        </div>
      </div>
      <div className="lg:ml-64">
        <MainFooter />
      </div>
    </div>
  );
}

export default Humen;
